from functools import reduce

def transform_data(data, map_func=None, filter_func=None, reduce_func=None, initial=None):
    """通用数据处理模板，支持映射、过滤和归约。"""
    result = data
    if map_func:
        result = map(map_func, result)
    if filter_func:
        result = filter(filter_func, result)
    if reduce_func:
        result = reduce(reduce_func, result) if initial is None else reduce(reduce_func, result, initial)
    return list(result) if not reduce_func else result
